with detail = 1 {
    with link = "line.dk.LBS" {
        let ls = path("d1.dk.lbs");

        with railway = :first :pax :removed {
            track(ls[:lau.ys, :tho.ya]);
            track(ls[:tho.ya, :sil.yl]);
        }
    }

    with link = "line.dk.LES" {
        let le = path("d1.dk.les.1");
        let es = path("d1.dk.les.2");

        with railway = :first :double :cat:ac25 :pax {
            track(le[:lun.ye, :vej.yg]);
            track(le[:vej.yg, :bra.yf]);
            track(le[:bra.yf, :bra.yt]);
            track(le[:bra.yt, :esb.ys]);
            track(le[:esb.ys, :esb]);
        }
        with railway = :first :pax {
            track(es[:esb.ys, :var.yn]);
            track(es[:var.yn, :tar.yn]);
            track(es[:tar.yn, :ske.ys]);
            track(es[:ske.ys, :ske.yv]);
            track(es[:ske.yv, :rin.yh]);
            track(es[:rin.yh, :vem.yl]);
            track(es[:vem.yl, :hol.yv]);
            track(es[:hol.yv, :str.yl]);
            track(es[:str.yl, :str]);
        }
    }

    with link = "line.dk.LST" {
        let ls = path("d1.dk.lst");

        with railway = :first :pax {
            track(ls[:lan.ya, :rod.ys]);
            track(ls[:rod.ys, :vib.ya]);
            track(ls[:vib.ya, :ski.yg]);
            track(ls[:ski.yg, :str.yl]);
        }
    }

    with link = "line.dk.LTY" {
        let lt = path("d1.dk.lty");

        with railway = :first :pax {
            track(lt[:lem.yt, :har.yt]);
            track(lt[:har.yt, :thh.yl]);
            track(lt[:thh.yl, :thh]);
            track(:removed, path("d1.dk.lty.kno")[:har.yt, :thh.yl]);
        }
    }
}

